package com.hospital.management.dao.impl;import com.hospital.management.dao.AdmissionTransferDao;import com.hospital.management.model.AdmissionTransfer;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;public class AdmissionTransferDaoImpl implements AdmissionTransferDao{public List<AdmissionTransfer>findByAdmissionId(Long id)throws SQLException{String q="SELECT t.*,fb.BED_NUMBER FROM_BED_NUMBER,fr.ROOM_NUMBER FROM_ROOM_NUMBER,tb.BED_NUMBER TO_BED_NUMBER,tr.ROOM_NUMBER TO_ROOM_NUMBER,u.USERNAME FROM ADMISSION_TRANSFERS t JOIN BEDS fb ON fb.BED_ID=t.FROM_BED_ID JOIN ROOMS fr ON fr.ROOM_ID=fb.ROOM_ID JOIN BEDS tb ON tb.BED_ID=t.TO_BED_ID JOIN ROOMS tr ON tr.ROOM_ID=tb.ROOM_ID JOIN USERS u ON u.USER_ID=t.TRANSFERRED_BY WHERE t.ADMISSION_ID=? ORDER BY t.TRANSFERRED_AT";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(q)){s.setLong(1,id);List<AdmissionTransfer>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next()){AdmissionTransfer t=new AdmissionTransfer();t.setTransferId(r.getLong("TRANSFER_ID"));t.setAdmissionId(id);t.setFromBedId(r.getLong("FROM_BED_ID"));t.setToBedId(r.getLong("TO_BED_ID"));t.setFromBedNumber(r.getString("FROM_BED_NUMBER"));t.setFromRoomNumber(r.getString("FROM_ROOM_NUMBER"));t.setToBedNumber(r.getString("TO_BED_NUMBER"));t.setToRoomNumber(r.getString("TO_ROOM_NUMBER"));t.setTransferReason(r.getString("TRANSFER_REASON"));t.setTransferredBy(r.getLong("TRANSFERRED_BY"));t.setTransferredByUsername(r.getString("USERNAME"));t.setTransferredAt(r.getTimestamp("TRANSFERRED_AT").toLocalDateTime());x.add(t);}}return x;}}public long create(Connection c,AdmissionTransfer t)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO ADMISSION_TRANSFERS(ADMISSION_ID,FROM_BED_ID,TO_BED_ID,TRANSFER_REASON,TRANSFERRED_BY)VALUES(?,?,?,?,?)",new String[]{"TRANSFER_ID"})){s.setLong(1,t.getAdmissionId());s.setLong(2,t.getFromBedId());s.setLong(3,t.getToBedId());s.setString(4,t.getTransferReason());s.setLong(5,t.getTransferredBy());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){return r.next()?r.getLong(1):0;}}}}
